public static MemberInfo FindProperty(LambdaExpression lambdaExpression)
    {
        Expression expressionToCheck = lambdaExpression.Body;
        while (true)
        {
            switch (expressionToCheck)
            {
                case MemberExpression { Member: var member, Expression.NodeType: ExpressionType.Parameter or ExpressionType.Convert }:
                    return member;
                case UnaryExpression { Operand: var operand }:
                    expressionToCheck = operand;
                    break;
                default:
                    throw new ArgumentException(
                        $"Expression '{lambdaExpression}' must resolve to top-level member and not any child object's properties. You can use ForPath, a custom resolver on the child type or the AfterMap option instead.",
                        nameof(lambdaExpression));
            }
        }
    }

static Expression BeSafe(Expression target, Expression expression, Func<Expression, Expression> update)
    {
        var fallback = Cache.GetOrAdd(target.Type);

        if (fallback != null)
        {
            // coalesce instead, a bit intrusive but fast...
            return update(Coalesce(target, fallback));
        }

        // target can be null, which is why we are actually here...
        var targetFallback = Constant(null, target.Type);

        // expression can be default or null, which is basically the same...
        var expressionFallback = !IsNullableOrReferenceType(expression.Type)
            ? (Expression)Default(expression.Type) : Constant(null, expression.Type);

        return Condition(Equal(target, targetFallback), expressionFallback, expression);
    }

public IDisposable RegisterHandler(Func<IInteractionContext<TInput, TOutput>, Task> handler)
    {
        ArgumentExceptionHelper.ThrowIfNull(handler);

        return RegisterHandlerCore(ContentHandler);

        // Yield before invoking the async handler so it is not run inside the current scheduler
        // trampoline (see #4351).
        IObservable<Unit> ContentHandler(IInteractionContext<TInput, TOutput> interaction) =>
            new TaskUnitObservable(InvokeAsync(interaction));

        async Task InvokeAsync(IInteractionContext<TInput, TOutput> interaction)
        {
            await YieldToCurrentContext().ConfigureAwait(false);
            await handler(interaction).ConfigureAwait(false);
        }
    }

IEnumerable<MessageTemplateToken> Tokenize(string messageTemplate)
    {
        if (messageTemplate.Length == 0)
        {
            yield return EmptyTextToken;
            yield break;
        }

        var nextIndex = 0;
        while (true)
        {
            var beforeText = nextIndex;
            var tt = ParseTextToken(nextIndex, messageTemplate, out nextIndex);
            if (nextIndex > beforeText)
                yield return tt;

            if (nextIndex == messageTemplate.Length)
                yield break;

            var beforeProp = nextIndex;
            var pt = ParsePropertyToken(nextIndex, messageTemplate, out nextIndex);
            if (beforeProp < nextIndex)
                yield return pt;

            if (nextIndex == messageTemplate.Length)
                yield break;
        }
    }

